const p=[{id:"opg-curve",annotationType:"panoramic_curve",tool:"panoramic_curve",title:"ОПТГ-дуга",detail:"Точки зубной дуги для панорамной реконструкции и поперечных срезов.",result:"структурная кривая",projection:"panoramic_reconstruction",unit:null,minimumPoints:3,requiresVolume:!0,requiresImplant:!1},{id:"distance-ruler",annotationType:"distance",tool:"measure_distance",title:"Линейка",detail:"Высота кости, ширина гребня или отступ до канала на выбранном срезе.",result:"мм после калибровки",projection:"oblique",unit:"mm",minimumPoints:2,requiresVolume:!0,requiresImplant:!1},{id:"ridge-width-ruler",annotationType:"distance",tool:"measure_distance",title:"Ширина гребня",detail:"Отдельная линейка ширины гребня для первичного скрининга диаметра импланта.",result:"ширина гребня в мм",projection:"oblique",unit:"mm",semanticRole:"ridge_width",minimumPoints:2,requiresVolume:!0,requiresImplant:!1},{id:"bone-height-ruler",annotationType:"distance",tool:"measure_distance",title:"Высота кости",detail:"Отдельная линейка высоты кости для первичного скрининга длины импланта.",result:"высота кости в мм",projection:"oblique",unit:"mm",semanticRole:"bone_height",minimumPoints:2,requiresVolume:!0,requiresImplant:!1},{id:"canal-clearance-ruler",annotationType:"distance",tool:"measure_distance",title:"Отступ до канала",detail:"Отдельная контрольная линейка от импланта до нижнечелюстного канала; не заменяет трассу канала и ось.",result:"контрольный отступ в мм",projection:"oblique",unit:"mm",semanticRole:"clearance",minimumPoints:2,requiresVolume:!0,requiresImplant:!0},{id:"angle-axis",annotationType:"angle",tool:"measure_angle",title:"Угол",detail:"Контроль наклона оси импланта, кортикальной пластинки или ортопедической оси.",result:"градусы",projection:"oblique",unit:"deg",minimumPoints:3,requiresVolume:!0,requiresImplant:!1},{id:"area-roi",annotationType:"area_roi",tool:"measure_area",title:"Контур площади",detail:"Контур дефекта, окна синус-лифтинга, графта или мягкотканной зоны.",result:"площадь после контура",projection:"axial",unit:"mm2",minimumPoints:3,requiresVolume:!0,requiresImplant:!1},{id:"volume-roi",annotationType:"volume_roi",tool:"measure_volume",title:"Контур объема",detail:"Объем дефекта, пазухи, графта или дыхательных путей.",result:"объем после сегмента",projection:"three_d_volume",unit:"mm3",minimumPoints:3,requiresVolume:!0,requiresImplant:!1},{id:"implant-axis",annotationType:"implant_axis",tool:"implant_axis",title:"Ось импланта",detail:"Черновик оси выбранного типоразмера для отступов, втулки и шаблона.",result:"ось + размер",projection:"oblique",unit:"mm",minimumPoints:2,requiresVolume:!0,requiresImplant:!0},{id:"nerve-canal",annotationType:"nerve_canal",tool:"nerve_canal",title:"Канал НЧ",detail:"Трасса нижнечелюстного канала как кривая, а не текстовая заметка.",result:"кривая канала",projection:"panoramic_reconstruction",unit:"mm",minimumPoints:3,requiresVolume:!0,requiresImplant:!1},{id:"density-probe",annotationType:"bone_density_probe",tool:"bone_density_probe",title:"Плотность",detail:"Точка ориентира плотности кости в зоне будущего ложа.",result:"HU/серые значения",projection:"axial",unit:"HU",minimumPoints:1,requiresVolume:!0,requiresImplant:!1},{id:"surgical-guide",annotationType:"surgical_guide",tool:"surgical_guide",title:"Шаблон",detail:"Маршрут втулки и передачи плана в лабораторию.",result:"пакет шаблона",projection:"three_d_volume",unit:null,minimumPoints:2,requiresVolume:!0,requiresImplant:!0}];function _(i){if(i.semanticRole)return i.semanticRole;const e=`${i.label??""} ${i.note??""}`.toLowerCase();return e.includes("ridge_width")||e.includes("ширин")?"ridge_width":e.includes("bone_height")||e.includes("высот")?"bone_height":e.includes("clearance")||e.includes("канал")||e.includes("отступ")?"clearance":"generic"}function q(i){return p.map(e=>{const l=[],o=new Set;i.annotations.forEach((t,d)=>{if(t.type!==e.annotationType||e.semanticRole&&_(t)!==e.semanticRole)return;const m=t.id?`${t.type}:${t.id}`:`${t.type}:local-${d}`;o.has(m)||(o.add(m),l.push(t))});const n=l.filter(t=>t.pointCount>=e.minimumPoints).length,r=l.length-n,u=e.requiresVolume&&!i.canPlan,a=e.requiresImplant&&!i.hasImplantPlan,s=n>0?"ready":u||a?"blocked":"draft",c=u?"нужна готовая КЛКТ/КТ-серия":a?"сначала выберите имплант":null;return{command:e,status:s,count:n,draftCount:r,statusLabel:n>0?`${n} готово`:r>0?`${r} начато`:s==="blocked"?"нужно действие":"готово к разметке",actionLabel:n>0||r>0?"Добавить еще":"Создать",blocker:c}})}export{q as b};
